32	<script is:inline>
33	  /** Create a progress indicator
34	   *  at the top */
35	  function createProgressBar() {
36	    // Create the main container div
37	    const progressContainer = document.createElement("div");
38	    progressContainer.className =
39	      "progress-container fixed top-0 z-10 h-1 w-full bg-skin-fill";
40	
41	    // Create the progress bar div
42	    const progressBar = document.createElement("div");
43	    progressBar.className = "progress-bar h-1 w-0 bg-skin-accent";
44	    progressBar.id = "myBar";
45	
46	    // Append the progress bar to the progress container
47	    progressContainer.appendChild(progressBar);
48	
49	    // Append the progress container to the document body or any other desired parent element
50	    document.body.appendChild(progressContainer);
51	  }
52	  createProgressBar();
53	
54	  /** Update the progress bar
55	   *  when user scrolls */
56	  function updateScrollProgress() {
57	    const winScroll =
58	      document.body.scrollTop || document.documentElement.scrollTop;
59	    const height =
60	      document.documentElement.scrollHeight -
61	      document.documentElement.clientHeight;
62	    const scrolled = (winScroll / height) * 100;
63	    if (document) {
64	      const myBar = document.getElementById("myBar");
65	      if (myBar) {
66	        myBar.style.width = scrolled + "%";
67	      }
68	    }
69	  }
70	  document.addEventListener("scroll", updateScrollProgress);
71	
72	  /** Attaches links to headings in the document,
73	   *  allowing sharing of sections easily */
74	  function addHeadingLinks() {
75	    let headings = Array.from(document.querySelectorAll("h2, h3, h4, h5, h6"));
76	    for (let heading of headings) {
77	      heading.classList.add("group");
78	      let link = document.createElement("a");
79	      link.innerText = "#";
80	      link.className = "heading-link hidden group-hover:inline-block ml-2";
81	      link.href = "#" + heading.id;
82	      link.ariaHidden = "true";
83	      heading.appendChild(link);
84	    }
85	  }
86	  addHeadingLinks();
87	
88	  /** Attaches copy buttons to code blocks in the document,
89	   * allowing users to copy code easily. */
90	  function attachCopyButtons() {
91	    let copyButtonLabel = "Copy";
92	    let codeBlocks = Array.from(document.querySelectorAll("pre"));
93	
94	    for (let codeBlock of codeBlocks) {
95	      let wrapper = document.createElement("div");
96	      wrapper.style.position = "relative";
97	
98	      let copyButton = document.createElement("button");
99	      copyButton.className =
100	        "copy-code absolute right-3 -top-3 rounded bg-skin-card px-2 py-1 text-xs leading-4 text-skin-base font-medium";
101	      copyButton.innerHTML = copyButtonLabel;
102	      codeBlock.setAttribute("tabindex", "0");
103	      codeBlock.appendChild(copyButton);
104	
105	      // wrap codebock with relative parent element
106	      codeBlock?.parentNode?.insertBefore(wrapper, codeBlock);
107	      wrapper.appendChild(codeBlock);
108	
109	      copyButton.addEventListener("click", async () => {
110	        await copyCode(codeBlock, copyButton);
111	      });
112	    }
113	
114	    async function copyCode(block, button) {
115	      let code = block.querySelector("code");
116	      let text = code?.innerText;
117	
118	      await navigator.clipboard.writeText(text ?? "");
119	
120	      // visual feedback that task is completed
121	      button.innerText = "Copied";
122	
123	      setTimeout(() => {
124	        button.innerText = copyButtonLabel;
125	      }, 700);
126	    }
127	  }
128	  attachCopyButtons();
129	
130	  /** Scrolls the document to the top when
131	   * the "Back to Top" button is clicked. */
132	  function backToTop() {
133	    document.querySelector("#back-to-top")?.addEventListener("click", () => {
134	      document.body.scrollTop = 0; // For Safari
135	      document.documentElement.scrollTop = 0; // For Chrome, Firefox, IE and Opera
136	    });
137	  }
138	  backToTop();
139	</script>
